import React, { useState } from 'react';
import './RevenueAnalytics.css';

interface RevenueData {
  month: string;
  revenue: number;
}

const RevenueAnalytics: React.FC = () => {
  const [selectedPeriod, setSelectedPeriod] = useState('Last 6 Months');

  const revenueData: RevenueData[] = [
    { month: 'Jul', revenue: 85000 },
    { month: 'Aug', revenue: 120000 },
    { month: 'Sep', revenue: 95000 },
    { month: 'Oct', revenue: 150000 },
    { month: 'Nov', revenue: 180000 },
    { month: 'Dec', revenue: 189000 },
  ];

  const maxRevenue = Math.max(...revenueData.map(item => item.revenue));

  const formatCurrency = (amount: number) => {
    return `₹${amount.toLocaleString('en-IN')}`;
  };

  const getBarHeight = (revenue: number) => {
    return (revenue / maxRevenue) * 200; // Max height of 200px
  };

  const periodOptions = [
    'Last 3 Months',
    'Last 6 Months',
    'Last 12 Months',
    'This Year'
  ];

  return (
    <div className="revenue-analytics">
      <div className="analytics-header">
        <div className="header-left">
          <h2>Revenue Analytics</h2>
          <p>Monthly revenue breakdown</p>
        </div>
        <div className="header-right">
          <div className="period-filter">
            <select 
              value={selectedPeriod} 
              onChange={(e) => setSelectedPeriod(e.target.value)}
              className="period-select"
            >
              {periodOptions.map((option) => (
                <option key={option} value={option}>
                  {option}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="chart-container">
        <div className="chart-area">
          <div className="y-axis">
            <div className="y-axis-label">₹2,00,000</div>
            <div className="y-axis-label">₹1,50,000</div>
            <div className="y-axis-label">₹1,00,000</div>
            <div className="y-axis-label">₹50,000</div>
            <div className="y-axis-label">₹0</div>
          </div>

          <div className="chart-bars">
            {revenueData.map((item, index) => (
              <div key={index} className="bar-container">
                <div 
                  className="revenue-bar"
                  style={{ height: `${getBarHeight(item.revenue)}px` }}
                >
                  <div className="bar-tooltip">
                    {formatCurrency(item.revenue)}
                  </div>
                </div>
                <div className="bar-label">{item.month}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="revenue-summary">
        <div className="summary-item">
          <span className="summary-label">Total Revenue</span>
          <span className="summary-value">{formatCurrency(revenueData.reduce((sum, item) => sum + item.revenue, 0))}</span>
        </div>
        <div className="summary-item">
          <span className="summary-label">Average Monthly</span>
          <span className="summary-value">{formatCurrency(Math.round(revenueData.reduce((sum, item) => sum + item.revenue, 0) / revenueData.length))}</span>
        </div>
        <div className="summary-item">
          <span className="summary-label">Highest Month</span>
          <span className="summary-value">{formatCurrency(maxRevenue)}</span>
        </div>
      </div>
    </div>
  );
};

export default RevenueAnalytics;
